mapper.select:
SELECT b.*, GROUP_CONCAT(c.name) AS categoryName, COUNT(bc2.id) AS availableQuantity FROM books b LEFT JOIN book_categories bc ON b.id = bc.book_id LEFT JOIN categories c ON bc.category_id = c.id LEFT JOIN book_copies bc2 ON b.id = bc2.book_id AND bc2.status = 'AVAILABLE' WHERE 1=1 AND b.`is_admin_registered` = 1
AND bc.category_id = #{categoryId}
AND MONTH(b.created_at) = #{month}
AND CEIL(DAY(b.created_at) / 7.0) = #{week}
GROUP BY b.id ORDER BY b.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT b.id)
FROM books b
LEFT JOIN book_categories bc ON b.id = bc.book_id
WHERE 1=1
AND b.`is_admin_registered` = 1

    AND bc.category_id = #{categoryId}


    AND MONTH(b.created_at) = #{month}


    AND CEIL(DAY(b.created_at) / 7.0) = #{week}
